use std::io::{self, BufRead};

fn main() {
    let mut line = String::new();
    let stdin = io::stdin();
    stdin
        .lock()
        .read_line(&mut line)
        .expect("could not read line!");

    let line = line.trim();
    let path = line
        .split('/')
        .filter(|s| !s.is_empty())
        .collect::<Vec<&str>>();

    println!("/{}", path.join("/"));
}
